                  </div>
                  <div className="text-right">
                    <Badge variant="outline" className="font-bold">
                      {contributor.total_points || 0} pts
                    </Badge>
                    <p className="text-xs text-muted-foreground mt-1">
                      {contributor.daily_activity?.length || 0} active days
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Activity className="w-5 h-5" />
              Activity Overview
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-2 gap-4 mb-6">
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{totalActivities.toLocaleString()}</div>
                <div className="text-sm text-muted-foreground">Total Activities</div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{averageActiveDays}</div>
                <div className="text-sm text-muted-foreground">Avg Active Days</div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{Math.round(totalActivities / totalContributors)}</div>
                <div className="text-sm text-muted-foreground">Avg Activities</div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{Math.round((recentlyActive / totalContributors) * 100)}%</div>
                <div className="text-sm text-muted-foreground">Weekly Active Rate</div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {topActivityTypes.map(([type, data]) => {
                const getActivityIcon = (activityType: string) => {
                  const typeStr = activityType.toLowerCase();
                  if (typeStr.includes('commit')) return <GitCommit className="w-4 h-4" />;
                  if (typeStr.includes('pr') || typeStr.includes('pull')) return <GitPullRequest className="w-4 h-4" />;
                  if (typeStr.includes('issue')) return <Activity className="w-4 h-4" />;
                  return <Activity className="w-4 h-4" />;
                };

                return (
                  <div key={type} className="p-3 border rounded-lg bg-gradient-to-br from-background to-muted/30">
                    <div className="flex items-center gap-2 mb-2">
                      {getActivityIcon(type)}
                      <span className="font-medium text-sm truncate">{type}</span>
                    </div>
                    <div className="space-y-1">
                      <div className="text-lg font-bold text-green-600 dark:text-green-400">{data.count}</div>
                      <div className="text-xs text-muted-foreground">{data.points} total points</div>
                    </div>
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import fs from "fs";
import path from "path";

const REPOS = [
  { name: "Mobile App", slug: "CircuitVerse/Mobile-App" },
  { name: "Vue Simulator", slug: "CircuitVerse/cv-frontend-vue" },
];

const HEADERS = {
  Accept: "application/vnd.github+json",
  Authorization: `Bearer ${process.env.GITHUB_TOKEN}`,
};

// ---------- GitHub API helpers ----------

async function fetchReleases(repo: string) {
  const res = await fetch(
    `https://api.github.com/repos/${repo}/releases`,
    { headers: HEADERS }
  );
  return res.json();
}

async function fetchCommitsBetween(
  repo: string,
  base: string,
  head: string
) {
  const res = await fetch(
    `https://api.github.com/repos/${repo}/compare/${base}...${head}`,
    { headers: HEADERS }
  );
  return res.json();
}

function extractContributors(commits: any[]) {
  const map: Record<string, number> = {};

  commits.forEach((c) => {
    const user = c.author?.login;
    if (!user) return;
    if (user.includes("bot")) return;

    map[user] = (map[user] || 0) + 1;
  });

  return Object.entries(map)
    .map(([username, commits]) => ({ username, commits }))
    .sort((a, b) => b.commits - a.commits)
    .slice(0, 5);
}

// ---------- Helpers ----------

function getReleaseSummary(body?: string) {
  if (!body) {
    return "This release includes internal improvements, bug fixes, and contributor updates.";
  }

  const firstLine = body
    .split("\n")
    .map((l) => l.trim())
    .find(Boolean);

  return (
    firstLine ||
    "This release includes internal improvements, bug fixes, and contributor updates."
  );
}

// ---------- MAIN ----------

async function run() {
  const allReleases: any[] = [];

  for (const repo of REPOS) {
    const releases = await fetchReleases(repo.slug);

    if (!Array.isArray(releases)) {
      console.error("Γ¥î Failed to fetch releases for", repo.slug);
      continue;
    }

    for (let i = 0; i < releases.length; i++) {
      const current = releases[i];
      const previous = releases[i + 1];

      let contributors: any[] = [];

      if (previous) {
        const compare = await fetchCommitsBetween(
          repo.slug,
          previous.tag_name,
          current.tag_name
        );

        contributors = extractContributors(compare.commits || []);
      }

      allReleases.push({
        repo: repo.name,
        repoSlug: repo.slug,
        version: current.tag_name,
        date: current.published_at?.slice(0, 10),
        summary: getReleaseSummary(current.body),
        contributors,
        githubUrl: current.html_url,
      });
    }
  }

  const outputPath = path.join(
    process.cwd(),
    "public/releases/releases.json"
  );

  fs.mkdirSync(path.dirname(outputPath), { recursive: true });
  fs.writeFileSync(outputPath, JSON.stringify(allReleases, null, 2));

  console.log("Γ£à Releases + contributors generated");
}

run();
